class MobilabApp extends StatelessWidget {
  const MobilabApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Mobilab',
      theme: MobilabTheme.dark(),
      home: const FutureBuilder(
        future: Innovation.build(),
        builder: (ctx, snapshot) {
          if (snapshot.hasData) return const SuccessView();
          return const CircularProgressIndicator();
        },
      ),
    );
  }
}
